public interface IFileUploadService
{
    Task<FileUploadResult> UploadFileAsync(IFormFile file, string subDirectory);
    Task<FileUploadResult> UploadAvatarAsync(IFormFile file);
    Task<FileUploadResult> UploadDocumentAsync(IFormFile file);
    bool IsAllowedFileType(string fileName, FileCategory category);
}

public enum FileCategory
{
    Avatar,
    Document
}

public class FileUploadResult
{
    public bool Success { get; set; }
    public string FilePath { get; set; } = string.Empty;
    public string FileName { get; set; } = string.Empty;
    public string OriginalFileName { get; set; } = string.Empty;
    public long FileSize { get; set; }
    public string ContentType { get; set; } = string.Empty;
    public string ErrorMessage { get; set; } = string.Empty;
}

public class FileUploadService : IFileUploadService
{
    private readonly IWebHostEnvironment _environment;

    private static readonly HashSet<string> AllowedAvatarExtensions = new(StringComparer.OrdinalIgnoreCase)
    {
        ".jpg", ".jpeg", ".png", ".gif", ".bmp", ".webp", ".svg"
    };

    private static readonly HashSet<string> AllowedDocumentExtensions = new(StringComparer.OrdinalIgnoreCase)
    {
        ".pdf",
        ".doc", ".docx",
        ".xls", ".xlsx",
        ".ppt", ".pptx",
        ".txt", ".csv",
        ".rtf",
        ".odt", ".ods", ".odp",
        ".jpg", ".jpeg", ".png", ".gif", ".bmp", ".webp", ".svg"
    };

    private const long MaxAvatarSize = 5 * 1024 * 1024; // 5 MB
    private const long MaxDocumentSize = 50 * 1024 * 1024; // 50 MB

    public FileUploadService(IWebHostEnvironment environment)
    {
        _environment = environment;
    }

    public bool IsAllowedFileType(string fileName, FileCategory category)
    {
        var extension = Path.GetExtension(fileName);
        return category switch
        {
            FileCategory.Avatar => AllowedAvatarExtensions.Contains(extension),
            FileCategory.Document => AllowedDocumentExtensions.Contains(extension),
            _ => false
        };
    }

    public async Task<FileUploadResult> UploadAvatarAsync(IFormFile file)
    {
        if (file == null || file.Length == 0)
        {
            return new FileUploadResult { Success = false, ErrorMessage = "No file provided." };
        }

        if (file.Length > MaxAvatarSize)
        {
            return new FileUploadResult { Success = false, ErrorMessage = $"Avatar file size exceeds the maximum allowed size of {MaxAvatarSize / (1024 * 1024)} MB." };
        }

        if (!IsAllowedFileType(file.FileName, FileCategory.Avatar))
        {
            return new FileUploadResult
            {
                Success = false,
                ErrorMessage = $"File type not allowed for avatars. Allowed types: {string.Join(", ", AllowedAvatarExtensions)}"
            };
        }

        return await UploadFileAsync(file, "avatars");
    }

    public async Task<FileUploadResult> UploadDocumentAsync(IFormFile file)
    {
        if (file == null || file.Length == 0)
        {
            return new FileUploadResult { Success = false, ErrorMessage = "No file provided." };
        }

        if (file.Length > MaxDocumentSize)
        {
            return new FileUploadResult { Success = false, ErrorMessage = $"Document file size exceeds the maximum allowed size of {MaxDocumentSize / (1024 * 1024)} MB." };
        }

        if (!IsAllowedFileType(file.FileName, FileCategory.Document))
        {
            return new FileUploadResult
            {
                Success = false,
                ErrorMessage = $"File type not allowed for documents. Allowed types: {string.Join(", ", AllowedDocumentExtensions)}"
            };
        }

        return await UploadFileAsync(file, "documents");
    }

    public async Task<FileUploadResult> UploadFileAsync(IFormFile file, string subDirectory)
    {
        try
        {
            var uploadsPath = Path.Combine(_environment.WebRootPath, "uploads", subDirectory);

            if (!Directory.Exists(uploadsPath))
            {
                Directory.CreateDirectory(uploadsPath);
            }

            var originalFileName = Path.GetFileNameWithoutExtension(file.FileName);
            var extension = Path.GetExtension(file.FileName);
            var uniqueFileName = $"{originalFileName}_{Guid.NewGuid():N}{extension}";
            var filePath = Path.Combine(uploadsPath, uniqueFileName);

            using (var stream = new FileStream(filePath, FileMode.Create))
            {
                await file.CopyToAsync(stream);
            }

            var relativePath = Path.Combine("uploads", subDirectory, uniqueFileName).Replace("\\", "/");

            return new FileUploadResult
            {
                Success = true,
                FilePath = $"/{relativePath}",
                FileName = uniqueFileName,
                OriginalFileName = file.FileName,
                FileSize = file.Length,
                ContentType = file.ContentType
            };
        }
        catch (Exception ex)
        {
            return new FileUploadResult
            {
                Success = false,
                ErrorMessage = $"An error occurred while uploading the file: {ex.Message}"
            };
        }
    }
}

[ApiController]
[Route("api/[controller]")]
public class UploadController : ControllerBase
{
    private readonly IFileUploadService _fileUploadService;

    public UploadController(IFileUploadService fileUploadService)
    {
        _fileUploadService = fileUploadService;
    }

    [HttpPost("avatar")]
    [RequestSizeLimit(5 * 1024 * 1024)]
    public async Task<IActionResult> UploadAvatar(IFormFile file)
    {
        var result = await _fileUploadService.UploadAvatarAsync(file);

        if (!result.Success)
        {
            return BadRequest(new { error = result.ErrorMessage });
        }

        return Ok(new
        {
            message = "Avatar uploaded successfully.",
            filePath = result.FilePath,
            fileName = result.FileName,
            originalFileName = result.OriginalFileName,
            fileSize = result.FileSize,
            contentType = result.ContentType
        });
    }

    [HttpPost("document")]
    [RequestSizeLimit(50 * 1024 * 1024)]
    public async Task<IActionResult> UploadDocument(IFormFile file)
    {
        var result = await _fileUploadService.UploadDocumentAsync(file);

        if (!result.Success)
        {
            return BadRequest(new { error = result.ErrorMessage });
        }

        return Ok(new
        {
            message = "Document uploaded successfully.",
            filePath = result.FilePath,
            fileName = result.FileName,
            originalFileName = result.OriginalFileName,
            fileSize = result.FileSize,
            contentType = result.ContentType
        });
    }

    [HttpPost("documents")]
    [RequestSizeLimit(200 * 1024 * 1024)]
    public async Task<IActionResult> UploadMultipleDocuments(List<IFormFile> files)
    {
        if (files == null || files.Count == 0)
        {
            return BadRequest(new { error = "No files provided." });
        }

        var results = new List<object>();
        var errors = new List<object>();

        foreach (var file in files)
        {
            var result = await _fileUploadService.UploadDocumentAsync(file);

            if (result.Success)
            {
                results.Add(new
                {
                    filePath = result.FilePath,
                    fileName = result.FileName,
                    originalFileName = result.OriginalFileName,
                    fileSize = result.FileSize,
                    contentType = result.ContentType
                });
            }
            else
            {
                errors.Add(new
                {
                    originalFileName = file.FileName,
                    error = result.ErrorMessage
                });
            }
        }

        return Ok(new
        {
            message = $"{results.Count} file(s) uploaded successfully. {errors.Count} file(s) failed.",
            uploadedFiles = results,
            failedFiles = errors
        });
    }
}